import{_ as e,o as a,c as o,ak as r}from"./chunks/framework.DwHlt8HN.js";const f=JSON.parse('{"title":"Work Modes","description":"XW37-BLE module work modes and configuration","frontmatter":{"title":"Work Modes","description":"XW37-BLE module work modes and configuration"},"headers":[],"relativePath":"docs/uart-coms/work-modes.md","filePath":"docs/uart-coms/work-modes.md"}'),n={name:"docs/uart-coms/work-modes.md"};function i(d,t,s,l,c,h){return a(),o("div",null,[...t[0]||(t[0]=[r('<h1 id="work-modes" tabindex="-1">Work Modes <a class="header-anchor" href="#work-modes" aria-label="Permalink to ‚ÄúWork Modes‚Äù">‚Äã</a></h1><h2 id="uart-configuration" tabindex="-1">UART Configuration <a class="header-anchor" href="#uart-configuration" aria-label="Permalink to ‚ÄúUART Configuration‚Äù">‚Äã</a></h2><p>The BLE and MCU communicate via UART. Default configuration:</p><ul><li><strong>Baud Rate:</strong> 9600</li><li><strong>Data Bits:</strong> 8</li><li><strong>Parity:</strong> None</li><li><strong>Stop Bits:</strong> 1</li></ul><h2 id="data-formats" tabindex="-1">Data Formats <a class="header-anchor" href="#data-formats" aria-label="Permalink to ‚ÄúData Formats‚Äù">‚Äã</a></h2><h3 id="transparent-mode" tabindex="-1">Transparent Mode <a class="header-anchor" href="#transparent-mode" aria-label="Permalink to ‚ÄúTransparent Mode‚Äù">‚Äã</a></h3><p>The module forwards MCU data to the App and App data to the MCU without modification. Data passes through directly.</p><h3 id="instruction-mode-at-mode" tabindex="-1">Instruction Mode (AT Mode) <a class="header-anchor" href="#instruction-mode-at-mode" aria-label="Permalink to ‚ÄúInstruction Mode (AT Mode)‚Äù">‚Äã</a></h3><p>AT commands can be sent via App or PC serial tools for configuration. Commands must end with <code>\\r\\n</code>.</p><h2 id="mode-switching" tabindex="-1">Mode Switching <a class="header-anchor" href="#mode-switching" aria-label="Permalink to ‚ÄúMode Switching‚Äù">‚Äã</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">Action</th><th style="text-align:left;">Command</th><th style="text-align:left;">Notes</th></tr></thead><tbody><tr><td style="text-align:left;">Enter AT Mode</td><td style="text-align:left;"><code>+++</code></td><td style="text-align:left;">No <code>\\r\\n</code> required</td></tr><tr><td style="text-align:left;">Exit AT Mode</td><td style="text-align:left;"><code>AT+exit\\r\\n</code></td><td style="text-align:left;">Returns to transparent mode</td></tr></tbody></table><h2 id="serial-switch-p03-pin-24" tabindex="-1">Serial Switch (P03/Pin 24) <a class="header-anchor" href="#serial-switch-p03-pin-24" aria-label="Permalink to ‚ÄúSerial Switch (P03/Pin 24)‚Äù">‚Äã</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">Signal Level</th><th style="text-align:left;">Mode</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>High</strong></td><td style="text-align:left;">Transparent mode</td></tr><tr><td style="text-align:left;"><strong>Low</strong></td><td style="text-align:left;">Low power mode</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p>Use P03 pin to switch between transparent mode and low power mode without sending AT commands.</p></div>',14)])])}const p=e(n,[["render",i]]);export{f as __pageData,p as default};
